registerPrompt(prompt: Prompt) { this.prompts.set(prompt.name, prompt); }
renderPrompt(promptName: string, variables: any): string { const prompt = this.prompts.get(promptName); if (!prompt) { throw new Error(Prompt ${promptName} not found); }
// 渲染模板 return templateEngine.render(prompt.template, variables); } }
### 动态提示生成 AI 模型可以请求特定的提示模板，并提供必要的参数来生成最终的提示： ``typescript async handleGetPrompt(request: GetPromptRequest): Promise&lt;GetPromptResponse&gt; { const prompt = this.promptManager.renderPrompt( request.params.name, request.params.arguments ); return { prompt: prompt }; } MCP 服务配置与管理 可视化配置界面 DeepChat 提供了友好的图形界面来配置和管理 MCP 服务：
服务列表 - 显示所有已配置的 MCP 服务 服务详情 - 查看和编辑服务配置 连接测试 - 测试与 MCP 服务的连接 权限管理 - 配置工具和资源的访问权限 配置文件管理 MCP 服务配置以 JSON 格式存储：
{ &#34;mcp&#34;: { &#34;servers&#34;: [ { &#34;id&#34;: &#34;local-server&#34;, &#34;name&#34;: &#34;Local MCP Server&#34;, &#34;transport&#34;: &#34;stdio&#34;, &#34;command&#34;: &#34;npx&#34;, &#34;args&#34;: [&#34;@modelcontextprotocol/server&#34;, &#34;start&#34;], &#34;enabled&#34;: true, &#34;permissions&#34;: { &#34;tools&#34;: [&#34;execute_code&#34;, &#34;http_request&#34;], &#34;resources&#34;: [&#34;local_files&#34;], &#34;prompts&#34;: [&#34;code_review&#34;, &#34;summarize&#34;] } } ] } } 小结 DeepChat 的 MCP 支持为 AI 模型提供了强大的扩展能力，使其能够访问外部资源、执行工具和使用预定义提示。其主要特点包括：
