// 程序主函数 export async function main() { // 解析命令行参数 const options = await parseArguments(); // 加载配置 const config = await loadConfig(options); // 设置主题 await setupTheme(config.theme); // 处理认证 await handleAuthentication(config); // 检查是否需要增加内存 await checkAndAdjustMemory(); // 初始化沙箱（如果配置了） await initializeSandbox(config.sandbox); // 处理非交互模式输入 if (!process.stdin.isTTY) { const input = await readStdin(); if (input.trim()) { // 在非交互模式下处理输入 await processNonInteractiveInput(input, config); return; } } // 启动交互式模式 await startInteractiveMode(config); } 这个函数展示了 CLI 的完整启动流程，从参数解析到交互式模式启动。
核心处理器实现 请求处理核心 核心处理器负责处理用户请求，这是 Qwen Code 的大脑：
// packages/core/src/core/processor.ts export class RequestProcessor { private contextManager: ContextManager; private modelInterface: ModelInterface; private toolExecutor: ToolExecutor; private responseParser: ResponseParser; constructor( contextManager: ContextManager, modelInterface: ModelInterface, toolExecutor: ToolExecutor, responseParser: ResponseParser ) { this.contextManager = contextManager; this.modelInterface = modelInterface; this.toolExecutor = toolExecutor; this.responseParser = responseParser; } async process(userInput: string): Promise&lt;string&gt; { // 将用户输入添加到上下文 this.contextManager.addMessage(&#39;user&#39;, userInput); // 构建完整的上下文 const context = this.buildFullContext(); // 调用模型 const modelResponse = await this.modelInterface.call(context); // 解析模型响应 const parsedResponse = this.responseParser.parse(modelResponse); // 处理工具调用 if (parsedResponse.toolCalls &amp;&amp; parsedResponse.toolCalls.length &gt; 0) { const toolResults = await this.executeTools(parsedResponse.toolCalls); // 将工具结果反馈给模型 const finalResponse = await this.modelInterface.callWithTools( context, toolResults ); // 将最终响应添加到上下文 this.contextManager.addMessage(&#39;assistant&#39;, finalResponse.text); return finalResponse.text; } // 将响应添加到上下文 this.contextManager.addMessage(&#39;assistant&#39;, parsedResponse.text); return parsedResponse.text; } private buildFullContext(): any { return { history: this.contextManager.getHistory(), tools: this.getAvailableTools() }; } private getAvailableTools(): Tool[] { // 返回当前可用的工具列表 return toolRegistry.getAllTools(); } private async executeTools(toolCalls: ToolCall[]): Promise&lt;ToolResult[]&gt; { const results: ToolResult[] = []; // 并行执行所有工具调用 const toolPromises = toolCalls.map(async (toolCall) =&gt; { try { const result = await this.toolExecutor.execute( toolCall.name, toolCall.arguments ); return { toolCallId: toolCall.id, result }; } catch (error) { return { toolCallId: toolCall.id, error: error.message }; } }); // 等待所有工具执行完成 const toolResults = await Promise.all(toolPromises); // 将结果添加到结果数组 results.push(...toolResults); return results; } } 请求处理的核心流程可以用下图表示：
sequenceDiagram participant User participant Processor participant Context participant Model participant Tools User->>Processor: 输入请求 Processor->>Context: 添加用户消息 Processor->>Context: 构建完整上下文 Processor->>Model: 调用模型 Model-->>Processor: 返回响应 Processor->>Processor: 解析响应 alt 有工具调用 Processor->>Tools: 执行工具 Tools-->>Processor: 返回结果 Processor->>Model: 反馈工具结果 Model-->>Processor: 返回最终响应 Processor->>Context: 添加助手消息 Processor-->>User: 返回最终结果 else 无工具调用 Processor->>Context: 添加助手消息 Processor-->>User: 返回结果 end 这个实现展示了 Qwen Code 如何处理用户的输入，调用 AI 模型，并根据需要执行工具。
工具实现详解 文件读取工具 read_file 工具是 Qwen Code 最基础也是最重要的工具之一：
// packages/core/src/tools/readFile.ts export const readFileTool: Tool = { name: &#39;read_file&#39;, description: &#39;读取文件内容。处理文本、图像(PNG, JPG, GIF, WEBP, SVG, BMP)和PDF文件。&#39;, parameters: { absolute_path: { type: &#39;string&#39;, description: &#39;文件的绝对路径&#39;, required: true }, limit: { type: &#39;number&#39;, description: &#39;可选：对于文本文件，最大读取行数&#39;, required: false }, offset: { type: &#39;number&#39;, description: &#39;可选：对于文本文件，开始读取的行偏移量&#39;, required: false } }, execute: async (params: any) =&gt; { // 验证参数 if (!params.absolute_path) { throw new Error(&#39;缺少必需参数: absolute_path&#39;); } // 验证路径是否为绝对路径 if (!path.isAbsolute(params.absolute_path)) { throw new Error(&#39;路径必须是绝对路径&#39;); } // 验证路径安全性 if (!isValidPath(params.absolute_path)) { throw new Error(&#39;路径不合法&#39;); } try { // 获取文件信息 const stats = await fs.promises.stat(params.absolute_path); // 检查是否为文件 if (!stats.isFile()) { throw new Error(&#39;指定路径不是文件&#39;); } // 根据文件类型处理 const fileType = getFileType(params.absolute_path); if (isTextFile(fileType)) { // 处理文本文件 return await handleTextFile(params); } else if (isImageFile(fileType)) { // 处理图像文件 return await handleImageFile(params.absolute_path); } else if (isPdfFile(fileType)) { // 处理PDF文件 return await handlePdfFile(params.absolute_path); } else { throw new Error(`不支持的文件类型: ${fileType}`); } } catch (error) { if (error.code === &#39;ENOENT&#39;) { throw new Error(`文件不存在: ${params.absolute_path}`); } throw error; } } }; // 处理文本文件 async function handleTextFile(params: any): Promise&lt;string&gt; { let content = await fs.promises.readFile(params.absolute_path, &#39;utf-8&#39;); // 如果指定了分页参数 if (params.limit || params.offset) { const lines = content.split(&#39;\n&#39;); const start = params.offset || 0; const end = params.limit ? start + params.limit : lines.length; content = lines.slice(start, end).join(&#39;\n&#39;); } return content; } // 处理图像文件 async function handleImageFile(filePath: string): Promise&lt;string&gt; { // 读取图像文件并转换为base64 const buffer = await fs.promises.readFile(filePath); const base64 = buffer.toString(&#39;base64&#39;); const mimeType = getMimeType(filePath); return `data:${mimeType};base64,${base64}`; } // 处理PDF文件 async function handlePdfFile(filePath: string): Promise&lt;string&gt; { // 这里可以使用pdf-parse等库来提取PDF文本内容 // 为简化，这里直接返回文件信息 const stats = await fs.promises.stat(filePath); return `PDF文件，大小: ${stats.size} 字节`; } 这个实现展示了 Qwen Code 如何安全地读取各种类型的文件，并根据文件类型进行不同的处理。
