// packages/core/src/tools/writeFile.ts export const writeFileTool: Tool = { name: &#39;write_file&#39;, description: &#39;将内容写入指定文件&#39;, parameters: { file_path: { type: &#39;string&#39;, description: &#39;文件的绝对路径&#39;, required: true }, content: { type: &#39;string&#39;, description: &#39;要写入的内容&#39;, required: true } }, execute: async (params: any) =&gt; { // 验证参数 if (!params.file_path) { throw new Error(&#39;缺少必需参数: file_path&#39;); } if (params.content === undefined) { throw new Error(&#39;缺少必需参数: content&#39;); } // 验证路径是否为绝对路径 if (!path.isAbsolute(params.file_path)) { throw new Error(&#39;文件路径必须是绝对路径&#39;); } // 验证路径安全性 if (!isValidPath(params.file_path)) { throw new Error(&#39;文件路径不合法&#39;); } try { // 确保目录存在 const dir = path.dirname(params.file_path); await fs.promises.mkdir(dir, { recursive: true }); // 写入文件 await fs.promises.writeFile(params.file_path, params.content, &#39;utf-8&#39;); return `成功写入文件: ${params.file_path}`; } catch (error) { throw new Error(`写入文件失败: ${error.message}`); } } }; 目录列表工具 list_directory 工具允许 AI 查看目录内容：
// packages/core/src/tools/listDirectory.ts export const listDirectoryTool: Tool = { name: &#39;list_directory&#39;, description: &#39;列出指定目录的内容&#39;, parameters: { path: { type: &#39;string&#39;, description: &#39;要列出的目录的绝对路径&#39;, required: true }, ignore: { type: &#39;array&#39;, description: &#39;要忽略的glob模式列表&#39;, required: false }, respect_git_ignore: { type: &#39;boolean&#39;, description: &#39;是否遵循.gitignore模式&#39;, required: false } }, execute: async (params: any) =&gt; { // 验证参数 if (!params.path) { throw new Error(&#39;缺少必需参数: path&#39;); } // 验证路径是否为绝对路径 if (!path.isAbsolute(params.path)) { throw new Error(&#39;路径必须是绝对路径&#39;); } // 验证路径安全性 if (!isValidPath(params.path)) { throw new Error(&#39;路径不合法&#39;); } try { // 检查路径是否存在且为目录 const stats = await fs.promises.stat(params.path); if (!stats.isDirectory()) { throw new Error(&#39;指定路径不是目录&#39;); } // 读取目录内容 const entries = await fs.promises.readdir(params.path, { withFileTypes: true }); // 过滤条目 let filteredEntries = entries; // 应用忽略模式 if (params.ignore &amp;&amp; Array.isArray(params.ignore)) { filteredEntries = filteredEntries.filter(entry =&gt; { return !params.ignore.some((pattern: string) =&gt; minimatch(entry.name, pattern) ); }); } // 应用.gitignore规则（如果配置了） if (params.respect_git_ignore !== false) { filteredEntries = await applyGitIgnoreFilter(filteredEntries, params.path); } // 格式化结果 const result = filteredEntries.map(entry =&gt; { return { name: entry.name, type: entry.isDirectory() ? &#39;directory&#39; : &#39;file&#39;, // 可以添加更多文件信息，如大小、修改时间等 }; }); return result; } catch (error) { if (error.code === &#39;ENOENT&#39;) { throw new Error(`目录不存在: ${params.path}`); } throw error; } } }; 模型接口实现 与 Qwen 模型通信 模型接口层负责与 Qwen 模型进行通信：
// packages/core/src/core/modelInterface.ts export class ModelInterface { private apiKey: string; private baseUrl: string; private model: string; private httpClient: AxiosInstance; constructor(config: ModelConfig) { this.apiKey = config.apiKey; this.baseUrl = config.baseUrl; this.model = config.model; // 创建HTTP客户端 this.httpClient = axios.create({ baseURL: this.baseUrl, timeout: 30000, // 30秒超时 headers: { &#39;Authorization&#39;: `Bearer ${this.apiKey}`, &#39;Content-Type&#39;: &#39;application/json&#39; } }); // 添加响应拦截器处理错误 this.httpClient.interceptors.response.use( response =&gt; response, error =&gt; { if (error.response) { // 服务器返回错误响应 throw new Error(`API错误: ${error.response.status} - ${error.response.data?.message || error.response.statusText}`); } else if (error.request) { // 请求发出但没有收到响应 throw new Error(&#39;网络错误: 无法连接到API服务器&#39;); } else { // 其他错误 throw new Error(`请求错误: ${error.message}`); } } ); } async call(context: any): Promise&lt;any&gt; { try { const response = await this.httpClient.post( `/models/${this.model}:generateContent`, { contents: context.history, tools: context.tools } ); return response.data; } catch (error) { throw error; } } async callWithTools(context: any, toolResults: ToolResult[]): Promise&lt;any&gt; { try { const response = await this.httpClient.post( `/models/${this.model}:generateContent`, { contents: context.history, tools: context.tools, tool_results: toolResults } ); return response.data; } catch (error) { throw error; } } } 安全机制实现 路径验证 为了确保安全性，Qwen Code 实现了严格的路径验证机制：
// packages/core/src/security/pathValidator.ts export function isValidPath(filePath: string): boolean { // 检查是否为绝对路径 if (!path.isAbsolute(filePath)) { return false; } // 检查是否包含路径遍历字符 if (filePath.includes(&#39;../&#39;) || filePath.includes(&#39;..\\&#39;)) { return false; } // 检查是否在允许的目录范围内 const allowedPaths = getAllowedPaths(); if (!allowedPaths.some(allowedPath =&gt; filePath.startsWith(allowedPath))) { return false; } // 检查是否访问了敏感目录 const sensitiveDirs = [&#39;/etc&#39;, &#39;/usr&#39;, &#39;/root&#39;, &#39;/sys&#39;, &#39;/proc&#39;]; if (sensitiveDirs.some(dir =&gt; filePath.startsWith(dir))) { return false; } return true; } function getAllowedPaths(): string[] { // 允许当前工作目录及其子目录 return [process.cwd()]; } 权限控制 Qwen Code 实现了细粒度的权限控制：
// packages/core/src/security/permissionManager.ts export class PermissionManager { private permissions: Map&lt;string, string[]&gt;; constructor() { // 默认权限配置 this.permissions = new Map([ [&#39;read_file&#39;, [&#39;read&#39;]], [&#39;write_file&#39;, [&#39;write&#39;]], [&#39;list_directory&#39;, [&#39;read&#39;]], [&#39;run_shell_command&#39;, [&#39;execute&#39;]], [&#39;google_web_search&#39;, [&#39;network&#39;]], // ... 其他工具权限 ]); } checkPermission(toolName: string, action: string): boolean { const toolPermissions = this.permissions.get(toolName); if (!toolPermissions) { return false; // 未注册的工具默认拒绝 } return toolPermissions.includes(action); } // 可以根据配置文件动态调整权限 updatePermissions(newPermissions: Record&lt;string, string[]&gt;): void { for (const [toolName, permissions] of Object.entries(newPermissions)) { this.permissions.set(toolName, permissions); } } } 上下文管理实现 对话历史管理 为了维持对话的连贯性，Qwen Code 实现了上下文管理机制：
// packages/core/src/core/contextManager.ts export class ContextManager { private history: Array&lt;{role: string, content: string}&gt; = []; private maxHistoryLength: number; constructor(maxHistoryLength: number = 10) { this.maxHistoryLength = maxHistoryLength; } addMessage(role: string, content: string): void { this.history.push({role, content}); // 限制历史记录长度，避免超出模型上下文限制 if (this.history.length &gt; this.maxHistoryLength) { // 保留系统消息和最新的几条消息 const systemMessages = this.history.filter(msg =&gt; msg.role === &#39;system&#39;); const recentMessages = this.history.slice(-this.maxHistoryLength); this.history = [...systemMessages, ...recentMessages]; } } getHistory(): Array&lt;{role: string, content: string}&gt; { return [...this.history]; } clear(): void { this.history = []; } // 可以根据需要添加系统消息 addSystemMessage(content: string): void { this.history.unshift({role: &#39;system&#39;, content}); } } 工具注册与管理 工具注册机制 Qwen Code 实现了灵活的工具注册机制：
// packages/core/src/tools/toolRegistry.ts export class ToolRegistry { private tools: Map&lt;string, Tool&gt; = new Map(); registerTool(tool: Tool): void { if (this.tools.has(tool.name)) { throw new Error(`工具已存在: ${tool.name}`); } this.tools.set(tool.name, tool); } getTool(name: string): Tool | undefined { return this.tools.get(name); } getAllTools(): Tool[] { return Array.from(this.tools.values()); } unregisterTool(name: string): boolean { return this.tools.delete(name); } } // 全局工具注册表 export const toolRegistry = new ToolRegistry(); // 在应用启动时注册所有工具 export function registerAllTools(): void { toolRegistry.registerTool(readFileTool); toolRegistry.registerTool(writeFileTool); toolRegistry.registerTool(listDirectoryTool); toolRegistry.registerTool(globTool); toolRegistry.registerTool(searchFileContentTool); toolRegistry.registerTool(replaceTool); toolRegistry.registerTool(runShellCommandTool); toolRegistry.registerTool(googleWebSearchTool); toolRegistry.registerTool(webFetchTool); toolRegistry.registerTool(saveMemoryTool); // ... 注册其他工具 } 工具注册与管理系统可以用下图表示：
