// packages/core/src/core/errorHandler.ts export class ErrorHandler { private logger: Logger; constructor(logger: Logger) { this.logger = logger; } handleError(error: Error): ErrorResponse { // 记录错误日志 this.logger.error(error.message, { stack: error.stack }); // 根据错误类型返回相应响应 if (error instanceof ValidationError) { return { type: &#39;validation_error&#39;, message: error.message, code: &#39;VALIDATION_ERROR&#39; }; } if (error instanceof PermissionError) { return { type: &#39;permission_error&#39;, message: error.message, code: &#39;PERMISSION_DENIED&#39; }; } if (error instanceof NetworkError) { return { type: &#39;network_error&#39;, message: error.message, code: &#39;NETWORK_ERROR&#39; }; } // 默认错误处理 return { type: &#39;unknown_error&#39;, message: &#39;发生未知错误&#39;, code: &#39;UNKNOWN_ERROR&#39; }; } } // 自定义错误类型 export class ValidationError extends Error { constructor(message: string) { super(message); this.name = &#39;ValidationError&#39;; } } export class PermissionError extends Error { constructor(message: string) { super(message); this.name = &#39;PermissionError&#39;; } } export class NetworkError extends Error { constructor(message: string) { super(message); this.name = &#39;NetworkError&#39;; } } 日志记录系统 Qwen Code 使用结构化日志记录重要事件：
// packages/core/src/core/logger.ts import debug from &#39;debug&#39;; export class Logger { private namespace: string; private debugLogger: debug.Debugger; constructor(namespace: string) { this.namespace = namespace; this.debugLogger = debug(`qwen-code:${namespace}`); } info(message: string, meta?: any): void { this.log(&#39;INFO&#39;, message, meta); } warn(message: string, meta?: any): void { this.log(&#39;WARN&#39;, message, meta); } error(message: string, meta?: any): void { this.log(&#39;ERROR&#39;, message, meta); } debug(message: string, meta?: any): void { this.log(&#39;DEBUG&#39;, message, meta); } private log(level: string, message: string, meta?: any): void { const timestamp = new Date().toISOString(); const logEntry = { timestamp, level, namespace: this.namespace, message, meta }; // 输出到控制台 console.log(JSON.stringify(logEntry)); // 使用 debug 库输出调试信息 if (level === &#39;DEBUG&#39;) { this.debugLogger(message, meta); } } } 总结 通过对 Qwen Code 核心代码的深度解读，我们可以看到这个项目在设计和实现上的许多精妙之处：
