关键组件：
主应用组件：管理整个 CLI 应用的生命周期 输入组件：处理用户输入 输出组件：显示 AI 响应和工具执行结果 状态组件：显示当前操作状态 // packages/cli/src/gemini.tsx (简化版) import React, { useState, useEffect } from &#39;react&#39;; import { Box, Text, useInput } from &#39;ink&#39;; const App: React.FC = () =&gt; { const [input, setInput] = useState(&#39;&#39;); const [output, setOutput] = useState(&#39;&#39;); useInput((char) =&gt; { if (char === &#39;\r&#39;) { // 处理回车键，发送请求到核心逻辑层 handleSubmit(input); } else { setInput(prev =&gt; prev + char); } }); const handleSubmit = async (query: string) =&gt; { // 调用核心逻辑层处理请求 const result = await core.processQuery(query); setOutput(result); }; return ( &lt;Box flexDirection=&#34;column&#34;&gt; &lt;Text&gt;Qwen Code CLI&lt;/Text&gt; &lt;Text color=&#34;green&#34;&gt;{output}&lt;/Text&gt; &lt;Text color=&#34;blue&#34;&gt;&gt; {input}&lt;/Text&gt; &lt;/Box&gt; ); }; 命令行参数解析 使用 commander.js 库处理命令行参数：
// packages/cli/src/cli.ts (简化版) import { Command } from &#39;commander&#39;; import { version } from &#39;../../package.json&#39;; const program = new Command(); program .version(version) .option(&#39;-c, --config &lt;path&gt;&#39;, &#39;配置文件路径&#39;) .option(&#39;-t, --theme &lt;name&gt;&#39;, &#39;主题名称&#39;) .action(async (options) =&gt; { // 初始化应用 await initializeApp(options); }); program.parse(); 核心逻辑层实现 请求处理流程 核心逻辑层负责处理用户请求，其主要流程如下：
请求接收：接收来自用户接口层的请求 上下文构建：构建包含历史对话和工具信息的上下文 模型调用：调用模型接口层与 Qwen 模型交互 响应处理：处理模型返回的响应 工具执行：根据需要执行工具 结果返回：将最终结果返回给用户接口层 // packages/core/src/core/processor.ts (简化版) class RequestProcessor { async processQuery(query: string): Promise&lt;string&gt; { // 1. 构建上下文 const context = this.buildContext(query); // 2. 调用模型 const response = await this.modelInterface.callModel(context); // 3. 处理响应 const processedResponse = this.handleResponse(response); // 4. 执行工具（如果需要） if (processedResponse.toolCalls) { const toolResults = await this.executeTools(processedResponse.toolCalls); // 将工具结果反馈给模型 const finalResponse = await this.modelInterface.callModelWithTools( context, toolResults ); return finalResponse; } return processedResponse.text; } } 请求处理流程可以用下图表示：
flowchart TD A[用户输入] --> B[请求接收] B --> C[上下文构建] C --> D[模型调用] D --> E[响应处理] E --> F{是否有工具调用?} F -->|是| G[工具执行] G --> H[工具结果反馈给模型] H --> I[最终响应] F -->|否| I I --> J[结果返回给用户] 上下文管理 为了维持对话的连贯性，Qwen Code 实现了上下文管理机制：
// packages/core/src/core/context.ts (简化版) class ContextManager { private history: Array&lt;{role: string, content: string}&gt; = []; addMessage(role: string, content: string) { this.history.push({role, content}); // 限制历史记录长度，避免超出模型上下文限制 if (this.history.length &gt; MAX_HISTORY_LENGTH) { this.history.shift(); } } getHistory(): Array&lt;{role: string, content: string}&gt; { return [...this.history]; } clear() { this.history = []; } } 工具执行层实现 工具接口设计 所有工具都实现统一的接口，确保一致性和可扩展性：
// packages/core/src/tools/tool.ts export interface Tool { name: string; description: string; parameters: { [key: string]: { type: string; description: string; required: boolean; }; }; execute: (params: any) =&gt; Promise&lt;any&gt;; } // 工具注册 export const tools: Tool[] = [ readFileTool, writeFileTool, listDirectoryTool, // ... 其他工具 ]; 文件系统工具实现 以 readFile 工具为例，展示工具实现细节：
// packages/core/src/tools/readFile.ts import { Tool } from &#39;./tool&#39;; import { promises as fs } from &#39;fs&#39;; import * as path from &#39;path&#39;; export const readFileTool: Tool = { name: &#39;read_file&#39;, description: &#39;读取文件内容&#39;, parameters: { absolute_path: { type: &#39;string&#39;, description: &#39;文件的绝对路径&#39;, required: true }, limit: { type: &#39;number&#39;, description: &#39;可选，要读取的最大行数&#39;, required: false }, offset: { type: &#39;number&#39;, description: &#39;可选，开始读取的行偏移量&#39;, required: false } }, execute: async (params) =&gt; { try { // 验证路径 if (!path.isAbsolute(params.absolute_path)) { throw new Error(&#39;路径必须是绝对路径&#39;); } // 读取文件 const content = await fs.readFile(params.absolute_path, &#39;utf-8&#39;); // 处理分页参数 if (params.limit || params.offset) { const lines = content.split(&#39;\n&#39;); const start = params.offset || 0; const end = params.limit ? start + params.limit : lines.length; return lines.slice(start, end).join(&#39;\n&#39;); } return content; } catch (error) { throw new Error(`读取文件失败: ${error.message}`); } } }; 工具执行机制 工具执行器负责调用具体工具并处理结果：
// packages/core/src/tools/executor.ts class ToolExecutor { private tools: Map&lt;string, Tool&gt;; constructor(tools: Tool[]) { this.tools = new Map(tools.map(tool =&gt; [tool.name, tool])); } async execute(toolName: string, params: any): Promise&lt;any&gt; { const tool = this.tools.get(toolName); if (!tool) { throw new Error(`未找到工具: ${toolName}`); } // 验证参数 this.validateParameters(tool, params); // 执行工具 return await tool.execute(params); } private validateParameters(tool: Tool, params: any) { for (const [name, param] of Object.entries(tool.parameters)) { if (param.required &amp;&amp; !(name in params)) { throw new Error(`缺少必需参数: ${name}`); } } } } 模型接口层实现 API 调用封装 模型接口层封装了与 Qwen 模型的通信细节：
// packages/core/src/core/modelInterface.ts import axios from &#39;axios&#39;; class ModelInterface { private apiKey: string; private baseUrl: string; private model: string; constructor(config: {apiKey: string, baseUrl: string, model: string}) { this.apiKey = config.apiKey; this.baseUrl = config.baseUrl; this.model = config.model; } async callModel(context: any): Promise&lt;any&gt; { try { const response = await axios.post( `${this.baseUrl}/models/${this.model}:generateContent`, { contents: context.history, tools: context.tools }, { headers: { &#39;Authorization&#39;: `Bearer ${this.apiKey}`, &#39;Content-Type&#39;: &#39;application/json&#39; } } ); return response.data; } catch (error) { throw new Error(`模型调用失败: ${error.message}`); } } } 响应解析 处理模型返回的响应并提取有用信息：
// packages/core/src/core/responseParser.ts class ResponseParser { parseResponse(response: any): ParsedResponse { // 提取文本内容 const text = response.candidates?.[0]?.content?.parts?.[0]?.text || &#39;&#39;; // 提取工具调用 const toolCalls = response.candidates?.[0]?.content?.parts ?.filter((part: any) =&gt; part.functionCall) ?.map((part: any) =&gt; part.functionCall) || []; return { text, toolCalls }; } } 安全管理层实现 权限控制 实现细粒度的权限控制机制：
// packages/core/src/security/permission.ts class PermissionManager { private permissions: Map&lt;string, string[]&gt;; constructor() { // 默认权限配置 this.permissions = new Map([ [&#39;read_file&#39;, [&#39;read&#39;]], [&#39;write_file&#39;, [&#39;write&#39;]], [&#39;run_shell_command&#39;, [&#39;execute&#39;]], // ... 其他工具权限 ]); } checkPermission(toolName: string, action: string): boolean { const toolPermissions = this.permissions.get(toolName); return toolPermissions ? toolPermissions.includes(action) : false; } } 沙箱机制 在隔离环境中执行潜在危险操作：
// packages/core/src/security/sandbox.ts class SandboxManager { async executeInSandbox(command: string): Promise&lt;any&gt; { // 创建隔离环境 const sandbox = await this.createSandbox(); try { // 在沙箱中执行命令 const result = await sandbox.execute(command); return result; } finally { // 清理沙箱 await this.destroySandbox(sandbox); } } private async createSandbox(): Promise&lt;Sandbox&gt; { // 实现沙箱创建逻辑 // 可能涉及 Docker 容器、虚拟机或其他隔离技术 } private async destroySandbox(sandbox: Sandbox): Promise&lt;void&gt; { // 实现沙箱销毁逻辑 } } 输入验证 对所有输入进行严格验证：
// packages/core/src/security/validator.ts class InputValidator { validatePath(path: string): boolean { // 检查路径是否合法 if (!path.startsWith(&#39;/&#39;)) { return false; // 必须是绝对路径 } if (path.includes(&#39;../&#39;)) { return false; // 禁止路径遍历 } // 检查是否在允许的目录范围内 const allowedPaths = this.getAllowedPaths(); return allowedPaths.some(allowed =&gt; path.startsWith(allowed)); } validateCommand(command: string): boolean { // 检查命令是否在允许列表中 const allowedCommands = this.getAllowedCommands(); return allowedCommands.some(allowed =&gt; command.startsWith(allowed)); } } 安全性管理的整体架构如下：
